import { DetailedHTMLProps, InputHTMLAttributes } from 'react'
import styled, { css } from 'styled-components'

import { Body } from '../typography/Body'

const Container = styled.div(
  ({ theme: { color, spacing, boxShadow, borderRadius } }) => css`
    display: flex;
    flex-direction: column;
    padding-bottom: 0;
    label {
      color: ${color.label};
      padding-bottom: ${spacing.xxs};
      &:first-letter {
        text-transform: uppercase;
      }
    }

    input {
      outline: none;
      padding: 13px 16px;
      box-sizing: border-box;
      border-radius: ${borderRadius.xs};
      border: none;
      color: ${color.primaryText};
      background: ${color.inputBackground};
      margin: 0;
      &:placeholder {
        color: ${color.inputHint};
      }
      &:focus,
      &:hover {
        box-shadow: ${boxShadow.outerBorder};
      }
    }

    input:focus + label {
      color: ${color.labelActive};
    }
  `
)

const ErrorMessage = styled(Body)(
  ({ theme: { color, spacing } }) => css`
    color: ${color.error};
    margin-top: ${spacing.xxs};
    font-size: 12px;
    min-height: 16px;
  `
)

type InputProps = {
  label?: string
  value?: any
  onChange?: (data: any) => void
  error?: string
} & DetailedHTMLProps<InputHTMLAttributes<HTMLInputElement>, HTMLInputElement>

export const Input = ({ label = '', type = 'text', id, error, ...otherProps }: InputProps) => (
  <Container>
    {label && (
      <Body type="label" htmlFor={id}>
        {label}
      </Body>
    )}
    <input id={id} aria-label={label} type={type} {...otherProps} autoComplete="off" />
    <ErrorMessage>{error || ' '}</ErrorMessage>
  </Container>
)

import * as React from 'react'
import styled, { css } from 'styled-components'

import { Button } from '../Button'
import { Body, Heading } from '../typography'

const ErrorContainer = styled.div(
  ({ theme: { spacing } }) => css`
    margin: 0 auto;
    padding: ${spacing.l} 0;
    display: flex;
    align-items: center;
    flex-direction: column;
  `
)

const ImageContainer = styled.div(
  ({ theme: { spacing } }) => css`
    text-align: center;
    margin-top: ${spacing.m};
    display: flex;
    justify-content: center;
    width: 100%;
  `
)

type ErrorBlockProps = {
  title: string
  image: React.ReactNode
  body: string
  buttonText: string
  onButtonClick: () => void
}

export const ErrorBlock = ({ title, image, body, buttonText, onButtonClick }: ErrorBlockProps) => (
  <ErrorContainer>
    <Heading level={2}>{title}</Heading>
    <ImageContainer>{image}</ImageContainer>
    <Body>{body}</Body>
    <Button onClick={onButtonClick}>{buttonText}</Button>
  </ErrorContainer>
)

import * as React from 'react'
import { CSSTransition } from 'react-transition-group'

import { useKey, useLockBodyScroll } from '../../hooks'
import { Button } from '../Button'
import { Heading } from '../typography'

import { SidebarContainer, SidebarContent, SidebarFooter, TopBar, Backdrop } from './Sidebar.styles'

type SidebarProps = {
  isOpen: boolean
  title: string
  onClose: () => void
  footer?: React.ReactNode
}

export const Sidebar: React.FC<React.PropsWithChildren<SidebarProps>> = ({
  children,
  footer,
  isOpen,
  title,
  onClose,
}) => {
  useKey('escape', onClose)
  useLockBodyScroll(isOpen)
  const contentRef = React.useRef(null)
  const backdropRef = React.useRef(null)

  return (
    <>
      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="sidebar"
        unmountOnExit
        nodeRef={contentRef}
      >
        <SidebarContainer data-testid="sidebar" ref={contentRef}>
          <TopBar>
            <Heading level={4}>{title}</Heading>
            <Button
              aria-label="close sidebar"
              data-testid="sidebar-close-btn"
              onClick={onClose}
              clear
              round
              icon="cross"
              iconSize={16}
            />
          </TopBar>
          <SidebarContent data-testid="sidebar-content">{children}</SidebarContent>
          {footer && <SidebarFooter data-testid="sidebar-footer">{footer}</SidebarFooter>}
        </SidebarContainer>
      </CSSTransition>

      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="backdrop"
        unmountOnExit
        nodeRef={backdropRef}
      >
        <Backdrop data-testid="Sidebar-backdrop" onClick={onClose} />
      </CSSTransition>
    </>
  )
}

